// ============================================================================
// q4mv_bf16_specialized.metal — BF16-faithful Q4 QMV kernels
// ============================================================================
//
// 4-bit quantized matrix-vector multiply (Q4 MLX format) specialized
// kernels, parallel to the 1-bit qmv_specialized.metal.  Weights are
// stored as 4-bit unsigned nibbles packed into uint32 (8 nibbles per
// uint32), with per-group BF16 scales and BF16 biases stored as raw uint16
// (affine quant).  Scales and biases are converted inline from the
// raw BF16 bit pattern to f32 for computation.  All output writes
// are BF16-rounded (truncated to 16-bit mantissa) to match MLX's
// BF16 arithmetic precision.
//
// Dequantization: w = scale * float(nibble) + bias
// Dot product:    row = scale * Sum(nibble_i * x_i)
//                     + bias  * Sum(x_i)
//
// Memory access pattern: weight reads use an interleaved SIMD layout
// where adjacent lanes read adjacent uint32 words for fully coalesced
// 128-byte memory transactions.  Each lane accumulates per-word
// scale/bias contributions since words from different groups are
// visited in interleaved order.
//
// Packing layout: each uint32 holds 8 sequential nibbles.
//   nibble i at bits [i*4 .. i*4+3].
//   Extract: (word >> (ni * 4)) & 0xFu
//   nibble_bytes_per_row = K / 2
//
// K and group_size are compile-time constants (constexpr).  Loop
// unrolling is explicitly disabled via pragma to keep register
// pressure low and preserve GPU occupancy (memory-bound kernels).
//
// The three macros SPEC_HIDDEN_K, SPEC_INTER_K, and SPEC_GS are
// prepended by the Zig build system before compilation.  This file
// must NOT define them.
// ============================================================================

#include <metal_stdlib>
using namespace metal;

// ----------------------------------------------------------------
// BF16 helpers — match MLX's bfloat16 arithmetic precision.
// ----------------------------------------------------------------

/// Convert a raw BF16 uint16 bit pattern to f32.
/// BF16 is the upper 16 bits of IEEE 754 f32: zero-extend
/// by shifting left 16.  Lossless.
inline float bf16_to_f32(ushort raw) {
    return as_type<float>(uint(raw) << 16);
}

/// Round an f32 value to BF16 precision by zeroing the lower
/// 16 mantissa bits.  This truncation (not round-to-nearest)
/// matches MLX's BF16 intermediate rounding behavior.
inline float bf16_round(float val) {
    return as_type<float>(as_type<uint>(val) & 0xFFFF0000u);
}

// ----------------------------------------------------------------
// Guard macros — fail loudly if the build system forgot them.
// ----------------------------------------------------------------

#ifndef SPEC_HIDDEN_K
    #error "SPEC_HIDDEN_K must be defined by the build system."
#endif

#ifndef SPEC_INTER_K
    #error "SPEC_INTER_K must be defined by the build system."
#endif

#ifndef SPEC_GS
    #error "SPEC_GS must be defined by the build system."
#endif

// Kept for buffer interface compatibility with generic dispatch.
// Only M is used — K and group_size are constexpr in each kernel.
struct QMVDims {
    uint M;
    uint K;
    uint group_size;
};

// ====================================================================
// Kernel 1: q4mv_spec_f16io — half in, half out
// ====================================================================
/// Specialized Q4 QMV with K = SPEC_HIDDEN_K and
/// group_size = SPEC_GS.  Half-precision input (constant cache)
/// and half-precision output.  Interleaved SIMD access pattern:
/// adjacent lanes read adjacent uint32 words for coalesced
/// memory transactions.  Per-word scale/bias accumulation.
///
/// Dispatch: threadgroups = ceil(M / 32), threads = 512.

kernel void q4mv_spec_f16io(
    device const uint8_t* packed_nibs [[buffer(0)]],
    device const ushort*  scales      [[buffer(1)]],
    device const ushort*  biases      [[buffer(2)]],
    constant half*        input       [[buffer(3)]],
    device half*          output      [[buffer(4)]],
    constant QMVDims&     dims        [[buffer(5)]],
    uint tgid [[threadgroup_position_in_grid]],
    uint tid  [[thread_index_in_threadgroup]])
{
    constexpr uint K = SPEC_HIDDEN_K;
    constexpr uint group_size = SPEC_GS;
    static_assert(K % 32 == 0,
        "K must be SIMD-aligned.");
    static_assert(K % group_size == 0,
        "K must be group-aligned.");
    static_assert(K >= 256,
        "K must be >= 256 for Q4 uint32 path.");
    static_assert(group_size % 8 == 0,
        "Group size must be 8-aligned.");
    const uint M = dims.M;

    const uint simdgroup_idx = tid / 32;
    const uint lane = tid % 32;
    const uint row0 = tgid * 32 + simdgroup_idx * 2;
    const uint row1 = row0 + 1;

    constexpr uint groups_per_row = K / group_size;
    constexpr uint words_per_row = K / 8;
    constexpr uint uint32s_per_lane = words_per_row / 32;
    constexpr uint nibble_bytes_per_row = K / 2;

    const bool row0_valid = row0 < M;
    const bool row1_valid = row1 < M;
    const uint safe_row0 = min(row0, M - 1);
    const uint safe_row1 = min(row1, M - 1);

    device const uint32_t* w32_r0 =
        (device const uint32_t*)(
            packed_nibs + safe_row0 * nibble_bytes_per_row);
    device const uint32_t* w32_r1 =
        (device const uint32_t*)(
            packed_nibs + safe_row1 * nibble_bytes_per_row);

    float acc0 = 0.0f, acc1 = 0.0f;

    // Interleaved access: adjacent lanes read adjacent words.
    #pragma clang loop unroll(disable)
    for (uint w = 0; w < uint32s_per_lane; w++) {
        const uint word_idx = w * 32 + lane;
        const uint col_base = word_idx * 8;
        const uint grp = col_base / group_size;

        const uint32_t word0 = w32_r0[word_idx];
        const uint32_t word1 = w32_r1[word_idx];

        float nd0 = 0.0f, nd1 = 0.0f, gs = 0.0f;
        for (uint ni = 0; ni < 8; ni++) {
            const float x = float(input[col_base + ni]);
            nd0 += float((word0 >> (ni * 4)) & 0xFu) * x;
            nd1 += float((word1 >> (ni * 4)) & 0xFu) * x;
            gs += x;
        }

        const uint sc0 = safe_row0 * groups_per_row + grp;
        const uint sc1 = safe_row1 * groups_per_row + grp;
        acc0 += bf16_to_f32(scales[sc0]) * nd0
              + bf16_to_f32(biases[sc0]) * gs;
        acc1 += bf16_to_f32(scales[sc1]) * nd1
              + bf16_to_f32(biases[sc1]) * gs;
    }

    acc0 = simd_sum(acc0);
    acc1 = simd_sum(acc1);

    if (row0_valid && lane == 0) {
        output[row0] = half(bf16_round(acc0));
    }
    if (row1_valid && lane == 0) {
        output[row1] = half(bf16_round(acc1));
    }
}

// ====================================================================
// Kernel 2: q4mv_spec_f16io_resadd — fused residual add
// ====================================================================
/// Identical to q4mv_spec_f16io but accumulates the f32 result
/// directly into the residual buffer (residual[row] += acc)
/// instead of writing half to an intermediate buffer.  Eliminates
/// one dispatch and one barrier per call site.
///
/// Dispatch: threadgroups = ceil(M / 32), threads = 512.
kernel void q4mv_spec_f16io_resadd(

pub fn forwardDecode(
    comptime Config: type,
    device: *const metal.Device,
    encoder: objc.Object,
    pipelines: *const TransformerPipelines,
    args: ForwardDecodeArgsT(Config.WeightBuffer),
) void {
    comptime {
        std.debug.assert(Config.num_layers > 0);
        std.debug.assert(Config.vocab_size > 0);
        std.debug.assert(Config.hidden_size > 0);
    }
    std.debug.assert(
        args.position < Config.max_context_length,
    );
    std.debug.assert(
        args.q_proj.len == Config.num_layers,
    );
    std.debug.assert(
        args.k_cache.len == Config.num_layers,
    );

    writeTokenId(args.token_ids, args.token_id);
    encodeEmbeddingLookup(
        Config,
        device,
        encoder,
        pipelines,
        args,
    );
    bufferBarrier(encoder);
    encodeAllBlocks(Config, device, encoder, pipelines, args);
    encodeFinalNormAndLMHead(
        Config,
        device,
        encoder,
        pipelines,
        args,
    );
}

/// Write a single u32 token ID into position 0 of the
/// token_ids buffer.  Safe before any GPU work is
/// dispatched on the same command buffer.
fn writeTokenId(
    token_ids_buf: objc.Object,
    token_id: u32,
) void {
    std.debug.assert(token_ids_buf.value != null);
    const ptr = token_ids_buf.msgSend(
        *anyopaque,
        "contents",
        .{},
    );
    const u32_ptr: [*]u32 = @ptrCast(@alignCast(ptr));
    u32_ptr[0] = token_id;
}

/// Dispatch 1-bit embedding lookup from a PackedBuffer.
/// Binds the same MTLBuffer at two offsets: bits at 0,
/// scales at scaleOffset.  Output goes to the residual
/// buffer (the block chain's running state).
fn encodeEmbeddingLookup(
    comptime Config: type,
    device: *const metal.Device,
    encoder: objc.Object,
    pipelines: *const TransformerPipelines,
    args: ForwardDecodeArgsT(Config.WeightBuffer),
) void {
    std.debug.assert(args.embedding.packed_count > 0);
    std.debug.assert(args.token_ids.value != null);

    const embed_dims = EmbedDims{

fn encodeAllBlocks(
    comptime Config: type,
    device: *const metal.Device,
    encoder: objc.Object,
    pipelines: *const TransformerPipelines,
    args: ForwardDecodeArgsT(Config.WeightBuffer),
) void {
    std.debug.assert(
        args.q_proj.len == Config.num_layers,
    );
    std.debug.assert(args.position + 1 > 0);

    const seq_len: u32 = args.position + 1;
    for (0..Config.num_layers) |i| {
        const idx: u32 = @intCast(i);
        const block_args = blockArgsFromDecodeT(
            Config.WeightBuffer,
            args,
            idx,
            seq_len,
        );
        forwardBlock(
            Config,
            device,
            encoder,
            pipelines,
            block_args,
        );
    }
}

/// Encode final RMSNorm on the residual, then dispatch
/// the LM head QMV to produce [vocab_size] f32 logits.
fn encodeFinalNormAndLMHead(
    comptime Config: type,
    device: *const metal.Device,
    encoder: objc.Object,
    pipelines: *const TransformerPipelines,
    args: ForwardDecodeArgsT(Config.WeightBuffer),
) void {
    std.debug.assert(args.lm_head.packed_count > 0);
    std.debug.assert(args.final_norm_scale.value != null);

    dispatchRMSNorm(
        device,
        encoder,
        if (comptime Config.quant_format == .q4_mlx)
            pipelines.rms_norm_bf16_f16out
        else
            pipelines.rms_norm_f16out,
        args.residual,
        args.final_norm_scale,
        args.norm_out,
        .{
            .hidden_size = Config.hidden_size,
            .num_tokens = 1,
            .eps = 1e-6,
        },
    );
    bufferBarrier(encoder);
    const lm_dims = QMVDims{
        .M = Config.vocab_size,
        .K = Config.hidden_size,
        .group_size = Config.group_size,
    };
    if (comptime Config.quant_format == .q4_mlx) {
        dispatchQ4MVf16in(
            device,
            encoder,
            args.lm_head,
            args.norm_out,
            args.logits,
            lm_dims,
        );
    } else {
        dispatchQMVf16in(
            device,
            encoder,
            args.lm_head,
            args.norm_out,
            args.logits,
            lm_dims,
        );
    }
}

/// Construct block args for one layer by indexing into the
/// per-layer slices of the decode args.  Activation scratch
/// buffers are shared across all layers.
fn blockArgsFromDecodeT(
    comptime WeightBuf: type,
    args: ForwardDecodeArgsT(WeightBuf),
    layer_index: u32,

pub fn forwardBlock(
    comptime Config: type,
    device: *const metal.Device,
    encoder: objc.Object,
    pipelines: *const TransformerPipelines,
    args: ForwardBlockArgsT(Config.WeightBuffer),
) void {
    comptime {
        std.debug.assert(Config.hidden_size > 0);
        std.debug.assert(Config.num_layers > 0);
    }
    std.debug.assert(args.seq_len > 0);
    std.debug.assert(
        args.position < Config.max_context_length,
    );
    std.debug.assert(
        args.seq_len <= Config.max_context_length,
    );

    encodeAttentionHalf(
        Config,
        device,
        encoder,
        pipelines,
        args,
    );
    encodeMLPHalf(
        Config,
        device,
        encoder,
        pipelines,
        args,
    );
}

// ============================================================================
// Full-model forward decode (Step 2d)
// ============================================================================

/// Parameterized full-model decode args — the weight buffer
/// type depends on the quantization format.  The alias
/// `ForwardDecodeArgs` preserves backward compatibility
/// with existing Q1 code.
pub fn ForwardDecodeArgsT(
    comptime WeightBuf: type,
) type {
    return struct {
        // Model-level quantized weights.
        embedding: WeightBuf,
        lm_head: WeightBuf,
        final_norm_scale: objc.Object,

        // Per-layer quantized weight buffers.
        q_proj: []const WeightBuf,
        k_proj: []const WeightBuf,
        v_proj: []const WeightBuf,
        o_proj: []const WeightBuf,
        gate_proj: []const WeightBuf,
        up_proj: []const WeightBuf,
        down_proj: []const WeightBuf,

        // Per-layer norm scale buffers (f32).
        attn_norm: []const metal.Buffer,
        ffn_norm: []const metal.Buffer,
        q_norm: []const metal.Buffer,
        k_norm: []const metal.Buffer,

        // Per-layer KV caches (f16).
        k_cache: []const metal.HalfBuffer,
        v_cache: []const metal.HalfBuffer,

        // Activation scratch (shared across all layers).
        residual: objc.Object,
        norm_out: objc.Object,
        q: objc.Object,
        k: objc.Object,
        v: objc.Object,
        attn_out: objc.Object,
        proj_out: objc.Object,
        attn_scratch: objc.Object,
        gate: objc.Object,
        up: objc.Object,
        mlp_out: objc.Object,

        // Forward pass I/O.
        token_ids: objc.Object,
        logits: objc.Object,

        // GPU completion flag for spin-wait.
        flag_buf: objc.Object,
        flag_ptr: *volatile u32,

        // Sequence state.
        token_id: u32,
        position: u32,
    };
}

pub const ForwardDecodeArgs =
    ForwardDecodeArgsT(metal.PackedBuffer);

/// Encode a full single-token decode pass into one compute
/// command encoder:
///   embedding lookup → N × forwardBlock → final RMSNorm →
///   LM head QMV → [vocab_size] f32 logits.
///
/// Writes the token ID into the `token_ids` buffer (CPU →
/// shared memory) before any GPU work is dispatched.  The
/// caller must not read `logits` until the command buffer
/// has completed (Rule 26).
///
/// Dispatch count: 1 + N×18 + 2 (embedding + N blocks ×
/// 18 kernels + final norm + LM head).
/// For Bonsai1_7B: 1 + 28×18 + 2 = 507.
pub fn forwardDecode(
    comptime Config: type,
    device: *const metal.Device,

fn encodeAttentionHalf(
    comptime Config: type,
    device: *const metal.Device,
    encoder: objc.Object,
    pipelines: *const TransformerPipelines,
    a: ForwardBlockArgsT(Config.WeightBuffer),
) void {
    encodeAttentionProjections(
        Config,
        device,
        encoder,
        pipelines,
        a,
    );
    encodeAttentionGather(
        Config,
        device,
        encoder,
        pipelines,
        a,
    );
}

/// Encode RMSNorm → Q/K/V projections → QK norms.
/// RoPE and KV cache update follow in a separate helper
/// to stay within the 70-line function limit.
fn encodeAttentionProjections(
    comptime Config: type,
    device: *const metal.Device,
    encoder: objc.Object,
    pipelines: *const TransformerPipelines,
    a: ForwardBlockArgsT(Config.WeightBuffer),
) void {
    const kv_qmv = QMVDims{
        .M = Config.kv_dim,
        .K = Config.hidden_size,
        .group_size = Config.group_size,
    };
    const q_qmv = QMVDims{
        .M = Config.query_dim,
        .K = Config.hidden_size,
        .group_size = Config.group_size,
    };
    // Fused norm needs K <= 4096 for threadgroup memory
    // and both single + pair pipelines available.
    const can_fuse_norm = comptime (Config.hidden_size % Config.group_size == 0) and
        (Config.hidden_size <= 4096) and
        (Config.hidden_size >= 256) and
        (Config.hidden_size / 32 <= Config.group_size);
    const use_fused_norm =
        if (comptime Config.quant_format == .q4_mlx)
            can_fuse_norm and
                device.spec_q4mv_fused_norm_f16io != null and
                device.spec_q4mv_fused_norm_f16io.?
                    .max_threads_per_group >= 512 and
                device.spec_q4mv_fused_norm_pair_f16io != null and
                device.spec_q4mv_fused_norm_pair_f16io.?
                    .max_threads_per_group >= 512 and
                q_qmv.K == device.spec_q4_hidden_K
        else
            can_fuse_norm and
                device.spec_qmv_fused_norm_f16io != null and
                device.spec_qmv_fused_norm_f16io.?
                    .max_threads_per_group >= 512 and
                device.spec_qmv_fused_norm_pair_f16io != null and
                device.spec_qmv_fused_norm_pair_f16io.?
                    .max_threads_per_group >= 512 and
                q_qmv.K == device.spec_hidden_K;
    if (use_fused_norm) {
        encodeAttnProjFusedNorm(
            Config,
            device,
            encoder,
            a,
            q_qmv,
            kv_qmv,
        );
    } else {
        encodeAttnProjSeparateNorm(
            Config,
            device,
            encoder,
            pipelines,
            a,
            q_qmv,
            kv_qmv,
        );
    }
    // Q/K norm + RoPE + KV cache update are now fused into
    // the GQA attention kernel (encodeAttentionGather).
    // Single barrier: wait for Q/K/V projection writes
    // before the fused GQA kernel reads them.
    bufferBarrier(encoder);
}

/// Fused-norm path: each QMV kernel reads the f32 residual
/// and f16 norm_scale directly, computes RMSNorm in TG memory.
/// Saves 1 RMSNorm dispatch + 1 barrier vs the separate path.
fn encodeAttnProjFusedNorm(
    comptime Config: type,
    device: *const metal.Device,
    encoder: objc.Object,
    a: ForwardBlockArgsT(Config.WeightBuffer),
    q_qmv: QMVDims,

fn encodeAttnProjFusedNorm(
    comptime Config: type,
    device: *const metal.Device,
    encoder: objc.Object,
    a: ForwardBlockArgsT(Config.WeightBuffer),
    q_qmv: QMVDims,
    kv_qmv: QMVDims,
) void {
    std.debug.assert(q_qmv.K == Config.hidden_size);
    std.debug.assert(kv_qmv.K == Config.hidden_size);
    if (comptime Config.quant_format == .q4_mlx) {
        // Q projection: fused norm + single Q4 QMV.
        dispatchQ4FusedNormQMVf16io(
            device,
            encoder,
            a.q_proj,
            a.residual,
            a.q,
            a.attn_norm_scale,
            q_qmv,
        );
        // KV projection: fused norm + paired Q4 QMV.
        dispatchQ4FusedNormPairQMVf16io(
            device,
            encoder,
            a.k_proj,
            a.v_proj,
            a.residual,
            a.k,
            a.v,
            a.attn_norm_scale,
            kv_qmv,
        );
    } else {
        // Q projection: fused norm + single QMV.
        dispatchFusedNormQMVf16io(
            device,
            encoder,
            a.q_proj,
            a.residual,
            a.q,
            a.attn_norm_scale,
            q_qmv,
        );
        // KV projection: fused norm + paired QMV.
        dispatchFusedNormPairQMVf16io(
            device,
            encoder,
            a.k_proj,
            a.v_proj,
            a.residual,
            a.k,
            a.v,
            a.attn_norm_scale,
            kv_qmv,
        );
    }
    // Barrier deferred to encodeAttentionProjections (caller).
}

/// Separate-norm path: RMSNorm → barrier → Q + fused KV.
/// Fallback when fused norm kernels are not available.
fn encodeAttnProjSeparateNorm(
    comptime Config: type,
    device: *const metal.Device,
    encoder: objc.Object,
    pipelines: *const TransformerPipelines,
    a: ForwardBlockArgsT(Config.WeightBuffer),
    q_qmv: QMVDims,
    kv_qmv: QMVDims,
) void {
    std.debug.assert(q_qmv.K == Config.hidden_size);
    std.debug.assert(kv_qmv.K == Config.hidden_size);
    dispatchRMSNorm(
        device,
        encoder,

fn encodeAttentionGather(
    comptime Config: type,
    device: *const metal.Device,
    encoder: objc.Object,
    pipelines: *const TransformerPipelines,
    a: ForwardBlockArgsT(Config.WeightBuffer),
) void {
    // Use the fused kernel that applies Q/K norm + RoPE +
    // KV cache update inside GQA when seq_len fits in TG
    // memory.  Falls back to separate dispatches otherwise.
    const TG_SEQ_LIMIT: u32 = 1024;
    if (a.seq_len <= TG_SEQ_LIMIT) {
        dispatchGQAAttentionFusedTG(
            device,
            encoder,
            pipelines.gqa_attention_fused_f16io_tg,
            a.q,
            a.k_cache,
            a.v_cache,
            a.attn_out,
            a.k,
            a.v,
            a.q_norm_scale,
            a.k_norm_scale,
            .{
                .num_query_heads = Config.num_query_heads,
                .num_kv_heads = Config.num_kv_heads,
                .head_dim = Config.head_dim,
                .seq_len = a.seq_len,
                .max_context_length = Config.max_context_length,
                .heads_per_kv_group = Config.heads_per_kv_group,
                .position = a.position,
                .eps = 1e-6,
                .rope_theta = Config.rope_theta,
            },
        );
    } else {
        // Long-sequence fallback: separate norm+RoPE+cache,
        // then the scratch-based GQA kernel.
        dispatchFusedNormRoPE(
            device,
            encoder,
            pipelines.fused_norm_rope_f16,
            a.q,
            a.q_norm_scale,
            .{
                .num_heads = Config.num_query_heads,
                .head_dim = Config.head_dim,
                .position = a.position,
                .eps = 1e-6,
                .rope_theta = Config.rope_theta,
            },
        );
        dispatchFusedKNormRoPEKVCache(
            device,
            encoder,
            pipelines.fused_k_norm_rope_kv_cache_f16,
            a.k,
            a.v,
            a.k_cache,
            a.v_cache,
            a.k_norm_scale,
            .{
                .num_kv_heads = Config.num_kv_heads,
                .head_dim = Config.head_dim,
                .position = a.position,
                .max_context_length = Config.max_context_length,
                .eps = 1e-6,
                .rope_theta = Config.rope_theta,
            },
        );
        bufferBarrier(encoder);
        dispatchGQAAttention(
            device,
            encoder,
            pipelines.gqa_attention_f16io,
            a.q,
            a.k_cache,
            a.v_cache,
            a.attn_out,
            a.attn_scratch,
            .{
                .num_query_heads = Config.num_query_heads,
                .num_kv_heads = Config.num_kv_heads,
                .head_dim = Config.head_dim,
                .seq_len = a.seq_len,
                .max_context_length = Config.max_context_length,
                .heads_per_kv_group = Config.heads_per_kv_group,
            },
        );
    }
    bufferBarrier(encoder);
    // Fused QMV + residual accumulate: the O-projection result
    // is added directly to the f32 residual (residual[row] += acc)
    // instead of writing f16 to proj_out then dispatching
    // residual_add_f16.  Saves one dispatch + one barrier.
    const o_dims = QMVDims{
        .M = Config.hidden_size,
        .K = Config.query_dim,
        .group_size = Config.group_size,
    };
    if (comptime Config.quant_format == .q4_mlx) {
        dispatchQ4MVf16ioResadd(
            device,
            encoder,
            a.o_proj,
            a.attn_out,
            a.residual,
            o_dims,
        );
    } else {
        dispatchQMVf16ioResadd(
            device,
            encoder,
            a.o_proj,
            a.attn_out,
            a.residual,
            o_dims,
        );
    }
    bufferBarrier(encoder);
}

/// Encode the MLP half of a decoder block:
/// RMSNorm → gate/up proj → SiLU⊙mul → down proj →
/// residual add.
fn encodeMLPHalf(
    comptime Config: type,
    device: *const metal.Device,
    encoder: objc.Object,
    pipelines: *const TransformerPipelines,
    a: ForwardBlockArgsT(Config.WeightBuffer),
) void {
    const mlp_qmv = QMVDims{
        .M = Config.intermediate_size,
        .K = Config.hidden_size,
        .group_size = Config.group_size,
    };
    // Gate and up projections share the same input and dims.
    // Best path: fuse FFN-RMSNorm + gate+up+SiLU into a
    // single kernel — saves 2 dispatches + 2 barriers per
    // block by reading the f32 residual directly.
    const can_fuse = comptime (Config.hidden_size % Config.group_size == 0) and
        (Config.hidden_size <= 6144) and
        (Config.hidden_size >= 256) and
        (Config.hidden_size / 32 <= Config.group_size);

fn encodeMLPHalf(
    comptime Config: type,
    device: *const metal.Device,
    encoder: objc.Object,
    pipelines: *const TransformerPipelines,
    a: ForwardBlockArgsT(Config.WeightBuffer),
) void {
    const mlp_qmv = QMVDims{
        .M = Config.intermediate_size,
        .K = Config.hidden_size,
        .group_size = Config.group_size,
    };
    // Gate and up projections share the same input and dims.
    // Best path: fuse FFN-RMSNorm + gate+up+SiLU into a
    // single kernel — saves 2 dispatches + 2 barriers per
    // block by reading the f32 residual directly.
    const can_fuse = comptime (Config.hidden_size % Config.group_size == 0) and
        (Config.hidden_size <= 6144) and
        (Config.hidden_size >= 256) and
        (Config.hidden_size / 32 <= Config.group_size);
    // Fused norm needs K <= 4096 for threadgroup memory.
    const can_fuse_norm = can_fuse and
        comptime (Config.hidden_size <= 4096);
    const use_fused_norm_silu =
        if (comptime Config.quant_format == .q4_mlx)
            can_fuse_norm and
                device.spec_q4mv_fused_norm_pair_silu_f16io !=
                    null and
                device.spec_q4mv_fused_norm_pair_silu_f16io.?
                    .max_threads_per_group >= 512 and
                mlp_qmv.K == device.spec_q4_hidden_K
        else
            can_fuse_norm and
                device.spec_qmv_fused_norm_pair_silu_f16io !=
                    null and
                device.spec_qmv_fused_norm_pair_silu_f16io.?
                    .max_threads_per_group >= 512 and
                mlp_qmv.K == device.spec_hidden_K;
    const use_fused_silu =
        if (comptime Config.quant_format == .q4_mlx)
            !use_fused_norm_silu and can_fuse and
                device.spec_q4mv_fused_pair_silu_f16io !=
                    null and
                device.spec_q4mv_fused_pair_silu_f16io.?
                    .max_threads_per_group >= 512 and
                mlp_qmv.K == device.spec_q4_hidden_K
        else
            !use_fused_norm_silu and can_fuse and
                device.spec_qmv_fused_pair_silu_f16io !=
                    null and
                device.spec_qmv_fused_pair_silu_f16io.?
                    .max_threads_per_group >= 512 and
                mlp_qmv.K == device.spec_hidden_K;
    if (use_fused_norm_silu) {
        // Fused norm+gate+up+SiLU: reads f32 residual
        // directly, computes RMSNorm in TG memory, then
        // gate+up QMV with SiLU.  Skips norm_out, gate,
        // and up buffers entirely.
        if (comptime Config.quant_format == .q4_mlx) {
            dispatchQ4FusedNormPairSiLUf16io(
                device,
                encoder,
                a.gate_proj,
                a.up_proj,
                a.residual,
                a.mlp_out,
                a.ffn_norm_scale,
                mlp_qmv,
            );
        } else {
            dispatchFusedNormPairSiLUf16io(
                device,
                encoder,
                a.gate_proj,
                a.up_proj,
                a.residual,
                a.mlp_out,
                a.ffn_norm_scale,
                mlp_qmv,
            );
        }
    } else if (use_fused_silu) {
        // Fused gate+up+SiLU: needs separate RMSNorm first.
        dispatchRMSNorm(
            device,
            encoder,
            if (comptime Config.quant_format == .q4_mlx)
                pipelines.rms_norm_bf16_f16out
            else
                pipelines.rms_norm_f16out,
            a.residual,
            a.ffn_norm_scale,
            a.norm_out,
            .{
                .hidden_size = Config.hidden_size,
                .num_tokens = 1,
                .eps = 1e-6,
            },
        );
        bufferBarrier(encoder);
        if (comptime Config.quant_format == .q4_mlx) {
            dispatchQ4MVFusedPairSiLUf16io(
                device,
                encoder,
                a.gate_proj,
                a.up_proj,
                a.norm_out,
                a.mlp_out,
                mlp_qmv,
            );
        } else {
            dispatchQMVFusedPairSiLUf16io(
                device,
                encoder,
                a.gate_proj,
                a.up_proj,
                a.norm_out,
                a.mlp_out,
                mlp_qmv,
            );
        }
    } else {
        // Non-fused-norm paths need separate RMSNorm.
        dispatchRMSNorm(
            device,
            encoder,
            if (comptime Config.quant_format == .q4_mlx)
                pipelines.rms_norm_bf16_f16out
            else
                pipelines.rms_norm_f16out,
            a.residual,
            a.ffn_norm_scale,
            a.norm_out,
            .{
                .hidden_size = Config.hidden_size,
                .num_tokens = 1,
                .eps = 1e-6,
            },
        );
        bufferBarrier(encoder);
        if (comptime Config.quant_format == .q4_mlx) {
            if (can_fuse) {
                dispatchQ4MVFusedPairf16io(
                    device,
                    encoder,
                    a.gate_proj,
                    a.up_proj,
                    a.norm_out,
                    a.gate,
                    a.up,
                    mlp_qmv,
                );
                bufferBarrier(encoder);
                dispatchSiLUElementwiseMul(
                    device,
                    encoder,
                    pipelines.silu_elementwise_mul_f16,
                    a.gate,
                    a.up,
                    a.mlp_out,
                    Config.intermediate_size,
                );
            } else {
                dispatchQ4MVf16io(
                    device,
                    encoder,
                    a.gate_proj,
                    a.norm_out,
                    a.gate,
                    mlp_qmv,
                );
                dispatchQ4MVf16io(
                    device,
                    encoder,
                    a.up_proj,
                    a.norm_out,
                    a.up,
                    mlp_qmv,
                );
                bufferBarrier(encoder);
                dispatchSiLUElementwiseMul(
                    device,
                    encoder,
                    pipelines.silu_elementwise_mul_f16,
                    a.gate,
                    a.up,
                    a.mlp_out,
                    Config.intermediate_size,
                );
            }
        } else {
            if (can_fuse) {
                dispatchQMVFusedPairf16io(
                    device,
                    encoder,
                    a.gate_proj,
                    a.up_proj,
                    a.norm_out,
                    a.gate,
                    a.up,
                    mlp_qmv,
                );
                bufferBarrier(encoder);
                dispatchSiLUElementwiseMul(
                    device,
                    encoder,
                    pipelines.silu_elementwise_mul_f16,
                    a.gate,
                    a.up,
                    a.mlp_out,
                    Config.intermediate_size,
                );
            } else {
                dispatchQMVf16io(
                    device,
                    encoder,
                    a.gate_proj,
                    a.norm_out,
                    a.gate,
                    mlp_qmv,
                );
                dispatchQMVf16io(
                    device,
                    encoder,
                    a.up_proj,
                    a.norm_out,
                    a.up,
                    mlp_qmv,
                );
                bufferBarrier(encoder);
                dispatchSiLUElementwiseMul(
                    device,
                    encoder,
                    pipelines.silu_elementwise_mul_f16,
                    a.gate,
                    a.up,
                    a.mlp_out,
                    Config.intermediate_size,
                );
            }
        }
    }
    bufferBarrier(encoder);
    // Fused QMV + residual accumulate: the down-projection
    // result is added directly to the f32 residual instead of
    // writing f16 to proj_out then dispatching residual_add_f16.
    // Saves one dispatch + one barrier.
    const down_dims = QMVDims{
        .M = Config.hidden_size,
        .K = Config.intermediate_size,
        .group_size = Config.group_size,
    };
    if (comptime Config.quant_format == .q4_mlx) {
        dispatchQ4MVf16ioResadd(
            device,
            encoder,
            a.down_proj,
            a.mlp_out,
            a.residual,
            down_dims,
        );
    } else {
        dispatchQMVf16ioResadd(
            device,
            encoder,
            a.down_proj,
            a.mlp_out,
            a.residual,
            down_dims,
        );
    }
    bufferBarrier(encoder);
}

// ============================================================================
// Sampling and autoregressive generation (Step 2f)
// ============================================================================

/// Parameters controlling token sampling from logits.
/// temperature=0 selects greedy (argmax).  Set top_k=0 and
/// top_p=1.0 to disable filtering.
pub const SamplingParams = struct {
    temperature: f32 = 0.0,
    top_k: u32 = 0,
    top_p: f32 = 1.0,
    seed: u64 = 42,
};

/// Timing and count results from a generate call.
pub const GenerateResult = struct {
    tokens_generated: u32,
    prefill_ns: u64,
    decode_ns: u64,
};

/// Options for the autoregressive generation loop.
/// Bundled into a struct to avoid mixing up slice parameters
/// at the call site (Rule 19).
pub const GenerateOpts = struct {
    prompt_ids: []const u32,
    params: SamplingParams,
    eos_ids: []const u32,
    output_tokens: []u32,
    /// Scratch buffer for top-k/top-p sorting.  Length must
    /// be >= vocab_size.  May be empty for greedy decoding.
    scratch: []f32,
    /// Index scratch for top-p sorting.  Same length
    /// requirement as `scratch`.
    indices: []u32,
    /// Optional buffer for per-token decode latencies
    /// (nanoseconds).  When non-null, must be at least as
    /// long as `output_tokens`.  Element [i] receives the
    /// wall-clock time for the decode step that runs while
    /// output_tokens[i] is the current token (GPU forward
    /// pass + CPU sampling).
    per_token_ns: ?[]u64 = null,
};

/// Find the index of the maximum value in a logits slice.
/// Returns 0 for a single-element slice.

kernel void q4mv_spec_f16io_resadd(
    device const uint8_t* packed_nibs [[buffer(0)]],
    device const ushort*  scales      [[buffer(1)]],
    device const ushort*  biases      [[buffer(2)]],
    constant half*        input       [[buffer(3)]],
    device float*         residual    [[buffer(4)]],
    constant QMVDims&     dims        [[buffer(5)]],
    uint tgid [[threadgroup_position_in_grid]],
    uint tid  [[thread_index_in_threadgroup]])
{
    constexpr uint K = SPEC_HIDDEN_K;
    constexpr uint group_size = SPEC_GS;
    static_assert(K % 32 == 0,
        "K must be SIMD-aligned.");
    static_assert(K % group_size == 0,
        "K must be group-aligned.");
    static_assert(K >= 256,
        "K must be >= 256 for Q4 uint32 path.");
    static_assert(group_size % 8 == 0,
        "Group size must be 8-aligned.");
    const uint M = dims.M;

    const uint simdgroup_idx = tid / 32;
    const uint lane = tid % 32;
    const uint row0 = tgid * 32 + simdgroup_idx * 2;
    const uint row1 = row0 + 1;

    constexpr uint groups_per_row = K / group_size;
    constexpr uint words_per_row = K / 8;
    constexpr uint uint32s_per_lane = words_per_row / 32;
    constexpr uint nibble_bytes_per_row = K / 2;

    const bool row0_valid = row0 < M;
    const bool row1_valid = row1 < M;
    const uint safe_row0 = min(row0, M - 1);
    const uint safe_row1 = min(row1, M - 1);

    device const uint32_t* w32_r0 =
        (device const uint32_t*)(
            packed_nibs + safe_row0 * nibble_bytes_per_row);
    device const uint32_t* w32_r1 =
        (device const uint32_t*)(
            packed_nibs + safe_row1 * nibble_bytes_per_row);

    float acc0 = 0.0f, acc1 = 0.0f;

    #pragma clang loop unroll(disable)
    for (uint w = 0; w < uint32s_per_lane; w++) {
        const uint word_idx = w * 32 + lane;
        const uint col_base = word_idx * 8;
        const uint grp = col_base / group_size;

        const uint32_t word0 = w32_r0[word_idx];
        const uint32_t word1 = w32_r1[word_idx];

        float nd0 = 0.0f, nd1 = 0.0f, gs = 0.0f;
        for (uint ni = 0; ni < 8; ni++) {
            const float x = float(input[col_base + ni]);
            nd0 += float((word0 >> (ni * 4)) & 0xFu) * x;
            nd1 += float((word1 >> (ni * 4)) & 0xFu) * x;
            gs += x;
        }

        const uint sc0 = safe_row0 * groups_per_row + grp;
        const uint sc1 = safe_row1 * groups_per_row + grp;
        acc0 += bf16_to_f32(scales[sc0]) * nd0
              + bf16_to_f32(biases[sc0]) * gs;
        acc1 += bf16_to_f32(scales[sc1]) * nd1
              + bf16_to_f32(biases[sc1]) * gs;
    }

    acc0 = simd_sum(acc0);
    acc1 = simd_sum(acc1);

    if (lane == 0) {
        if (row0_valid) residual[row0] += bf16_round(acc0);
        if (row1_valid) residual[row1] += bf16_round(acc1);
    }
}

// ====================================================================
// Kernel 3: q4mv_spec_fused_pair_f16io — two matrices, one input
// ====================================================================
/// Specialized fused-pair Q4 QMV with K = SPEC_HIDDEN_K.  Processes
/// two weight matrices (A and B) against a single shared input
/// vector in one dispatch, halving kernel launch overhead for
/// K/V projection and gate/up projection pairs.
///
/// Uses 1 row per simdgroup (not 2) to manage register pressure
/// from the two concurrent weight streams.
///
/// Dispatch: threadgroups = ceil(M / 16), threads = 512.
kernel void q4mv_spec_fused_pair_f16io(
    device const uint8_t* packed_a   [[buffer(0)]],
    device const ushort*  scales_a   [[buffer(1)]],
    device const ushort*  biases_a   [[buffer(2)]],

kernel void q4mv_spec_mg_f16io_resadd(
    device const uint8_t* packed_nibs [[buffer(0)]],
    device const ushort*  scales      [[buffer(1)]],
    device const ushort*  biases      [[buffer(2)]],
    device const half*    input       [[buffer(3)]],
    device float*         residual    [[buffer(4)]],
    constant QMVDims&     dims        [[buffer(5)]],
    uint tgid [[threadgroup_position_in_grid]],
    uint tid  [[thread_index_in_threadgroup]])
{
    constexpr uint K = SPEC_INTER_K;
    constexpr uint group_size = SPEC_GS;
    static_assert(K % 32 == 0,
        "K must be SIMD-aligned.");
    static_assert(K % group_size == 0,
        "K must be a multiple of group_size.");
    static_assert(group_size % 8 == 0,
        "Group size must be 8-column-aligned "
        "for uint32 boundary alignment.");
    static_assert(K >= 256,
        "K must be >= 256 for Q4 uint32 path.");
    static_assert(K % 512 == 0,
        "K must be divisible by 512 "
        "for cooperative TG load.");
    static_assert(K <= 12288,
        "K must fit in 24 KB threadgroup memory.");
    const uint M = dims.M;

    // Cache input in threadgroup memory.
    threadgroup half tg_input[K];
    constexpr uint elems_per_thread = K / 512;
    for (uint j = 0; j < elems_per_thread; j++) {
        tg_input[tid * elems_per_thread + j] =
            input[tid * elems_per_thread + j];
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    const uint simdgroup_idx = tid / 32;
    const uint lane = tid % 32;
    const uint row0 = tgid * 32 + simdgroup_idx * 2;
    const uint row1 = row0 + 1;

    const bool row0_valid = row0 < M;
    const bool row1_valid = row1 < M;

    constexpr uint groups_per_row = K / group_size;
    constexpr uint nibble_bytes_per_row = K / 2;
    constexpr uint words_per_row = K / 8;
    constexpr uint uint32s_per_lane = words_per_row / 32;

    const uint safe_row0 = min(row0, M - 1);
    const uint safe_row1 = min(row1, M - 1);

    device const uint32_t* w32_r0 =
        (device const uint32_t*)(
            packed_nibs + safe_row0 * nibble_bytes_per_row);
    device const uint32_t* w32_r1 =
        (device const uint32_t*)(
            packed_nibs + safe_row1 * nibble_bytes_per_row);

    float acc0 = 0.0f, acc1 = 0.0f;

    // Interleaved access with per-word group accumulation.
    #pragma clang loop unroll(disable)
    for (uint w = 0; w < uint32s_per_lane; w++) {
        const uint word_idx = w * 32 + lane;
        const uint col_base = word_idx * 8;
        const uint grp = col_base / group_size;

        const uint32_t word0 = w32_r0[word_idx];
        const uint32_t word1 = w32_r1[word_idx];

        float nd0 = 0.0f, nd1 = 0.0f, gs = 0.0f;
        for (uint ni = 0; ni < 8; ni++) {
            const float x = float(tg_input[col_base + ni]);
            nd0 += float((word0 >> (ni * 4)) & 0xFu) * x;
            nd1 += float((word1 >> (ni * 4)) & 0xFu) * x;
            gs += x;
        }

        const uint sc0 =
            safe_row0 * groups_per_row + grp;
        const uint sc1 =
            safe_row1 * groups_per_row + grp;
        acc0 += bf16_to_f32(scales[sc0]) * nd0
              + bf16_to_f32(biases[sc0]) * gs;
        acc1 += bf16_to_f32(scales[sc1]) * nd1
              + bf16_to_f32(biases[sc1]) * gs;
    }

    acc0 = simd_sum(acc0);
    acc1 = simd_sum(acc1);

    if (lane == 0) {
        if (row0_valid) residual[row0] += bf16_round(acc0);
        if (row1_valid) residual[row1] += bf16_round(acc1);
    }
}

// ====================================================================
// Kernel 6: q4mv_spec_fused_pair_silu_f16io — gate/up + SiLU fused
// ====================================================================
/// Fused gate+up projection with SiLU activation and elementwise
/// multiply: output[row] = silu(gate_row) * up_row.  Eliminates
/// the separate SiLU+elementwise_mul dispatch and two barriers
/// per block.
///
/// Uses 1 row per simdgroup (not 2) to keep register pressure
/// low enough for max_threads >= 512 despite the extra exp()
/// in the SiLU output stage.
///
/// Dispatch: threadgroups = ceil(M / 16), threads = 512.
kernel void q4mv_spec_fused_pair_silu_f16io(
    device const uint8_t* packed_a  [[buffer(0)]],
    device const ushort*  scales_a  [[buffer(1)]],
    device const ushort*  biases_a  [[buffer(2)]],

fn dispatchQ4MVf16ioResadd(
    device: *const metal.Device,
    encoder: objc.Object,
    q4_buffer: metal.Q4Buffer,
    input_buffer: objc.Object,
    residual_buffer: objc.Object,
    dims: QMVDims,
) void {
    std.debug.assert(dims.M > 0);
    std.debug.assert(dims.K > 0);
    std.debug.assert(dims.K % 32 == 0);
    std.debug.assert(dims.group_size > 0);
    std.debug.assert(q4_buffer.packed_count > 0);

    // Select single-group (hidden) or multi-group (inter)
    // pipeline based on K dimension.
    const use_sg =
        if (device.spec_q4mv_f16io_resadd) |s|
            s.max_threads_per_group >= 512 and
                dims.K == device.spec_q4_hidden_K
        else
            false;
    const use_mg =
        if (device.spec_q4mv_mg_f16io_resadd) |s|
            s.max_threads_per_group >= 512 and
                dims.K == device.spec_q4_inter_K
        else
            false;
    const pipeline = if (use_sg)
        device.spec_q4mv_f16io_resadd.?
    else if (use_mg)
        device.spec_q4mv_mg_f16io_resadd.?
    else
        unreachable; // Q4 resadd requires specialized pipelines.

    metal.setQ4Buffer(encoder, q4_buffer, 0);
    setRawBuffer(encoder, input_buffer, 0, 3);
    setRawBuffer(encoder, residual_buffer, 0, 4);
    metal.setBytes(encoder, QMVDims, &dims, 5);

    const rows_per_tg: u32 = 32;
    const threads_per_tg: u32 = 512;
    const threadgroups =
        (dims.M + rows_per_tg - 1) / rows_per_tg;
    const grid = metal.MTLSize{
        .width = @as(c_ulong, threadgroups),
        .height = 1,
        .depth = 1,
    };
    const group = metal.MTLSize{
        .width = @as(c_ulong, threads_per_tg),
        .height = 1,
        .depth = 1,
    };
    device.dispatchCustom(encoder, pipeline, grid, group);
}

/// Dispatch Q4 fused-pair QMV: f16 input, two f16 outputs.
/// Two Q4 weight matrices share the same input vector.
/// buffer(0-2): Q4 A, buffer(3): input, buffer(4): output A,
/// buffer(5-7): Q4 B, buffer(8): output B, buffer(9): dims.
fn dispatchQ4MVFusedPairf16io(
    device: *const metal.Device,
    encoder: objc.Object,
    packed_a: metal.Q4Buffer,
    packed_b: metal.Q4Buffer,
    input_buffer: objc.Object,
    output_a: objc.Object,
    output_b: objc.Object,

fn dispatchQ4MVFusedPairSiLUf16io(
    device: *const metal.Device,
    encoder: objc.Object,
    packed_a: metal.Q4Buffer,
    packed_b: metal.Q4Buffer,
    input_buffer: objc.Object,
    output: objc.Object,
    dims: QMVDims,
) void {
    std.debug.assert(dims.M > 0);
    std.debug.assert(dims.K > 0);
    std.debug.assert(dims.K % 32 == 0);
    std.debug.assert(dims.group_size > 0);
    std.debug.assert(packed_a.packed_count > 0);
    std.debug.assert(packed_b.packed_count > 0);

    const pipeline =
        device.spec_q4mv_fused_pair_silu_f16io orelse
        unreachable; // Q4 fused SiLU requires specialized.

    metal.setQ4Buffer(encoder, packed_a, 0);
    setRawBuffer(encoder, input_buffer, 0, 3);
    setRawBuffer(encoder, output, 0, 4);
    metal.setQ4Buffer(encoder, packed_b, 5);
    metal.setBytes(encoder, QMVDims, &dims, 8);

    const rows_per_tg: u32 = 16;
    const threads_per_tg: u32 = 512;
    const threadgroups =
        (dims.M + rows_per_tg - 1) / rows_per_tg;
    const grid = metal.MTLSize{
        .width = @as(c_ulong, threadgroups),
        .height = 1,
        .depth = 1,
    };
    const group = metal.MTLSize{
        .width = @as(c_ulong, threads_per_tg),
        .height = 1,
        .depth = 1,
    };
    device.dispatchCustom(encoder, pipeline, grid, group);
}

/// Dispatch Q4 fused RMSNorm + single QMV: f32 residual in,
/// f16 output.  Computes RMSNorm cooperatively in TG memory.
/// buffer(0-2): Q4 weights, buffer(3): f32 residual,
/// buffer(4): f16 output, buffer(5): dims,
/// buffer(6): f16 norm_scale.
fn dispatchQ4FusedNormQMVf16io(
    device: *const metal.Device,
    encoder: objc.Object,
    q4_buffer: metal.Q4Buffer,
    residual: objc.Object,
    output: objc.Object,
    norm_scale: objc.Object,
    dims: QMVDims,
) void {
    std.debug.assert(dims.M > 0);
    std.debug.assert(dims.K > 0);
    std.debug.assert(dims.K % 32 == 0);
    std.debug.assert(dims.group_size > 0);
    std.debug.assert(q4_buffer.packed_count > 0);
    std.debug.assert(residual.value != null);
    std.debug.assert(norm_scale.value != null);

    const pipeline =
        device.spec_q4mv_fused_norm_f16io orelse
        unreachable; // Q4 fused norm requires specialized.

    metal.setQ4Buffer(encoder, q4_buffer, 0);
    setRawBuffer(encoder, residual, 0, 3);
    setRawBuffer(encoder, output, 0, 4);
    metal.setBytes(encoder, QMVDims, &dims, 5);
    setRawBuffer(encoder, norm_scale, 0, 6);

    const rows_per_tg: u32 = 32;
    const threads_per_tg: u32 = 512;
